patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 838e952c024c..a0ebdd255034 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -14697,6 +14697,11 @@ BoUpSLP::isGatherShuffledSingleRegisterEntry(
   // Pair.first is the offset to the vector, while Pair.second is the index of
   // scalar in the list.
   for (const std::pair<unsigned, int> &Pair : EntryLanes) {
+    // Ensure Pair.first is within bounds of Entries vector to avoid out-of-bounds access.
+    if (Pair.first >= Entries.size()) {
+      Entries.clear();
+      return std::nullopt;
+    }
     unsigned Idx = Part * VL.size() + Pair.second;
     Mask[Idx] =
         Pair.first * VF +

